const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient({
    endpoint: process.env.COSMOS_ENDPOINT,
    key: process.env.COSMOS_KEY
});

const database = cosmosClient.database(process.env.COSMOS_DATABASE);
const container = database.container(process.env.COSMOS_CONTAINER);

async function processBatch(items, context) {
    const results = [];
    
    for (const item of items) {
        try {
            const processed = {
                id: item.id,
                originalData: item.data,
                processedAt: new Date().toISOString(),
                status: 'completed',
                transformedData: transformData(item.data),
                checksum: generateChecksum(item.data)
            };
            
            results.push(processed);
            
            if (context.invocationId) {
                context.log(`Processed item: ${item.id}`);
            }
        } catch (error) {
            results.push({
                id: item.id,
                status: 'failed',
                error: error.message,
                processedAt: new Date().toISOString()
            });
            
            if (context.invocationId) {
                context.error(`Failed to process item ${item.id}: ${error.message}`);
            }
        }
    }
    
    return results;
}

function transformData(data) {
    if (!data) return null;
    
    if (typeof data === 'string') {
        return data.trim().toUpperCase();
    }
    
    if (typeof data === 'object') {
        const transformed = {};
        for (const [key, value] of Object.entries(data)) {
            if (value !== null && value !== undefined) {
                transformed[key] = typeof value === 'string' ? value.trim() : value;
            }
        }
        return transformed;
    }
    
    return data;
}

function generateChecksum(data) {
    const crypto = require('crypto');
    const str = typeof data === 'string' ? data : JSON.stringify(data);
    return crypto.createHash('sha256').update(str).digest('hex');
}

async function fetchDataInBatches(query, batchSize, context) {
    const batches = [];
    let continuationToken = undefined;
    let totalFetched = 0;
    
    do {
        const querySpec = {
            query: query,
            parameters: []
        };
        
        const options = {
            maxItemCount: batchSize,
            continuationToken: continuationToken
        };
        
        const { resources, continuationToken: nextToken } = await container.items
            .query(querySpec, options)
            .fetchNext();
        
        if (resources && resources.length > 0) {
            batches.push(resources);
            totalFetched += resources.length;
            
            if (context.invocationId) {
                context.log(`Fetched batch: ${resources.length} items (Total: ${totalFetched})`);
            }
        }
        
        continuationToken = nextToken;
        
    } while (continuationToken);
    
    return batches;
}

async function saveProcessedResults(results, context) {
    const outputContainer = database.container(process.env.COSMOS_OUTPUT_CONTAINER || 'processed-data');
    const savedItems = [];
    
    for (const result of results) {
        try {
            const { resource } = await outputContainer.items.upsert(result);
            savedItems.push(resource);
        } catch (error) {
            if (context.invocationId) {
                context.error(`Failed to save result for item ${result.id}: ${error.message}`);
            }
        }
    }
    
    return savedItems;
}

async function updateProcessingStatus(batchId, status, context) {
    const statusContainer = database.container(process.env.COSMOS_STATUS_CONTAINER || 'processing-status');
    
    const statusDoc = {
        id: batchId,
        status: status,
        timestamp: new Date().toISOString(),
        invocationId: context.invocationId
    };
    
    try {
        await statusContainer.items.upsert(statusDoc);
    } catch (error) {
        if (context.invocationId) {
            context.error(`Failed to update status: ${error.message}`);
        }
    }
}

app.http('batchDataProcessor', {
    methods: ['POST', 'GET'],
    authLevel: 'function',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        const batchId = `batch-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
        
        context.log(`Starting batch processing: ${batchId}`);
        
        try {
            await updateProcessingStatus(batchId, 'started', context);
            
            const batchSize = parseInt(process.env.BATCH_SIZE || '100', 10);
            const query = process.env.COSMOS_QUERY || 'SELECT * FROM c WHERE c.processed != true';
            
            context.log(`Fetching data with query: ${query}`);
            const batches = await fetchDataInBatches(query, batchSize, context);
            
            context.log(`Total batches to process: ${batches.length}`);
            
            let totalProcessed = 0;
            let totalFailed = 0;
            const allResults = [];
            
            for (let i = 0; i < batches.length; i++) {
                const batch = batches[i];
                context.log(`Processing batch ${i + 1}/${batches.length} with ${batch.length} items`);
                
                const results = await processBatch(batch, context);
                allResults.push(...results);
                
                const succeeded = results.filter(r => r.status === 'completed').length;
                const failed = results.filter(r => r.status === 'failed').length;
                
                totalProcessed += succeeded;
                totalFailed += failed;
                
                await saveProcessedResults(results, context);
                
                context.log(`Batch ${i + 1} complete: ${succeeded} succeeded, ${failed} failed`);
                
                const elapsed = Date.now() - startTime;
                if (elapsed > 540000) {
                    context.warn('Approaching timeout limit, stopping processing');
                    break;
                }
            }
            
            const duration = Date.now() - startTime;
            
            await updateProcessingStatus(batchId, 'completed', context);
            
            const summary = {
                batchId: batchId,
                status: 'success',
                totalProcessed: totalProcessed,
                totalFailed: totalFailed,
                batchesProcessed: batches.length,
                durationMs: duration,
                timestamp: new Date().toISOString()
            };
            
            context.log(`Batch processing complete: ${JSON.stringify(summary)}`);
            
            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(summary)
            };
            
        } catch (error) {
            context.error(`Batch processing failed: ${error.message}`);
            context.error(error.stack);
            
            await updateProcessingStatus(batchId, 'failed', context);
            
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    batchId: batchId,
                    status: 'error',
                    error: error.message,
                    timestamp: new Date().toISOString()
                })
            };
        }
    }
});

